#[php_class]
#[php(name = "Kreuzcrawl\\KreuzcrawlApi")]
pub struct KreuzcrawlApi;

#[php_impl]
impl KreuzcrawlApi {
    /**
     * Create a new crawl engine with the given configuration.
     *
     * If `config` is `None`, uses [`CrawlConfig::default()`].
     * Returns an error if the configuration is invalid.
     */
    pub fn create_engine(config: Option<&CrawlConfig>) -> PhpResult<CrawlEngineHandle> {
        let config_core: Option<kreuzcrawl::CrawlConfig> = config.map(|v| v.clone().into());
        let result = kreuzcrawl::create_engine(config_core)
            .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
        Ok(CrawlEngineHandle {
            inner: Arc::new(result),
        })
    }

    /**
     * Scrape a single URL, returning extracted page data.
     */
    pub fn scrape(engine: &CrawlEngineHandle, url: String) -> PhpResult<ScrapeResult> {
        WORKER_RUNTIME.block_on(async {
            let result = kreuzcrawl::scrape(&engine.inner, &url)
                .await
                .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
            Ok(result.into())
        })
    }

    /**
     * Crawl a website starting from `url`, following links up to the configured depth.
     */
    pub fn crawl(engine: &CrawlEngineHandle, url: String) -> PhpResult<CrawlResult> {
        WORKER_RUNTIME.block_on(async {
            let result = kreuzcrawl::crawl(&engine.inner, &url)
                .await
                .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
            Ok(result.into())
        })
    }

    /**
     * Discover all pages on a website by following links and sitemaps.
     */
    pub fn map_urls(engine: &CrawlEngineHandle, url: String) -> PhpResult<MapResult> {
        WORKER_RUNTIME.block_on(async {
            let result = kreuzcrawl::map_urls(&engine.inner, &url)
                .await
                .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
            Ok(result.into())
        })
    }

    /**
     * Scrape multiple URLs concurrently.
     */
    pub fn batch_scrape(engine: &CrawlEngineHandle, urls: Vec<String>) -> PhpResult<Vec<BatchScrapeResult>> {
        WORKER_RUNTIME.block_on(async {
            let result = kreuzcrawl::batch_scrape(&engine.inner, urls)
                .await
                .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
            Ok(result.into_iter().map(Into::into).collect())
        })
    }

    /**
     * Crawl multiple seed URLs concurrently, each following links to configured depth.
     */
    pub fn batch_crawl(engine: &CrawlEngineHandle, urls: Vec<String>) -> PhpResult<Vec<BatchCrawlResult>> {
        WORKER_RUNTIME.block_on(async {
            let result = kreuzcrawl::batch_crawl(&engine.inner, urls)
                .await
                .map_err(|e| ext_php_rs::exception::PhpException::default(e.to_string()))?;
            Ok(result.into_iter().map(Into::into).collect())
        })
    }
}

